// Format the digest. EDIT the `to` address for your team inbox/channel.
const kpi = $input.first().json;
const today = new Intl.DateTimeFormat('en-CA', { timeZone: 'Europe/Berlin' }).format(new Date());
const row = (label, v) => `<tr><td style="padding:6px 12px;border-bottom:1px solid #e2e8f0">${label}</td><td style="padding:6px 12px;border-bottom:1px solid #e2e8f0;text-align:right"><b>${v}</b></td></tr>`;
const html = `<div style="font-family:Arial,Helvetica,sans-serif;max-width:520px;margin:0 auto;padding:24px;color:#0f172a">` +
  `<h2 style="margin:0 0 4px">Schulab daily KPIs</h2>` +
  `<p style="margin:0 0 16px;color:#64748b;font-size:13px">${today} · last 24h vs totals</p>` +
  `<table style="border-collapse:collapse;width:100%;font-size:14px">` +
  row('New signups (24h)', kpi.new_users) +
  row('New enrollments (24h)', kpi.new_enrollments) +
  row('New bookings (24h)', kpi.new_bookings) +
  row('New marketing opt-ins (24h)', kpi.new_marketing_optins) +
  row('Total users', kpi.total_users) +
  row('Total enrollments', kpi.total_enrollments) +
  row('Total certificates', kpi.total_certificates) +
  `</table></div>`;
return [{ json: { body: {
  from: 'Schulab <noreply@schulab.com>',
  to: ['admin@schulab.com'],
  subject: `Schulab KPIs ${today}: ${kpi.new_users} signups, ${kpi.new_enrollments} enrollments`,
  html,
} } }];
